const tokenomics = {
  id: 'tokenomics',
  title: 'Tokenomics',
  emoji: '🪙',
  color: '#D97706',
  gradient: ['#B45309', '#D97706'],
  description: 'Design token economies that create lasting value, align incentives, and sustain protocols.',
  category: 'Business',
  modules: [
    {
      id: 'tokenomics_beg',
      level: 'beginner',
      title: 'Token Economics Basics',
      emoji: '📊',
      description: 'What makes a token valuable and how to evaluate token design.',
      color: '#D97706',
      lessons: [
        { id: 'tok_beg_l1', title: 'What Makes Tokens Valuable?', slides: [
          { type: 'intro', title: 'Value Beyond Speculation', body: 'Most crypto tokens are primarily speculative assets — they\'re valuable because others expect them to be more valuable later. But some tokens capture fundamental economic value from protocol activity. Understanding the difference is the foundation of tokenomics literacy.' },
          { type: 'text', title: 'The Value Capture Question', body: 'The key question for any token: how does protocol success accrue value to the token? Revenue sharing (holders earn % of fees). Governance rights (control over high-value protocol parameters). Utility (required to use the protocol). Collateral (must be staked to access service). Deflationary burn (usage reduces supply). A token with none of these is purely speculative — dependent on the "greater fool" theory.' },
          { type: 'text', title: 'The Utility Token Spectrum', body: 'Pure governance (UNI early stage): holders can vote but receive no revenue. Governance + fees (CRV with veCRV): locked holders earn 50% of protocol fees. Protocol utility (LINK): required by protocols using Chainlink oracle data. Work token (ETH post-merge): required to stake to validate Ethereum, earn staking yield. Each model creates different demand characteristics and valuation frameworks.' },
          { type: 'highlight', title: 'Supply and Demand Fundamentals', body: 'Token price = f(demand, supply). Demand drivers: new buyers, utility requirements, staking demand, speculation. Supply drivers: emission schedule, inflation rate, vesting unlocks. A token with strong demand drivers and constrained supply (deflationary mechanics, long-term locking) has structural price support. Most tokens are highly inflationary early — emissions outpace demand, creating constant sell pressure.' },
          { type: 'text', title: 'Market Cap Reality Check', body: 'Fully Diluted Valuation (FDV): price × total supply. Market cap: price × circulating supply. Many tokens have low circulating supply market caps but huge FDV (most tokens locked/unvested). If FDV is $10B but market cap is $500M, $9.5B in tokens will enter circulation over time — creating massive sell pressure. Always check FDV, not just market cap.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Token value requires real capture mechanisms: fees, utility, staking, or deflationary burns. Supply and demand fundamentals determine price. Always evaluate FDV (fully diluted valuation) not just current market cap — circulating supply expansion is persistent sell pressure.' },
        ]},
        { id: 'tok_beg_l2', title: 'Token Distribution Models', slides: [
          { type: 'intro', title: 'Who Gets the Tokens?', body: 'Token distribution determines who controls the protocol, how much initial sell pressure exists, and whether the community feels the launch was fair. Distribution mistakes are catastrophic and irreversible — get this right before launch.' },
          { type: 'text', title: 'The Standard Allocation Template', body: 'Community/ecosystem: 40-50% (largest share → decentralization and community alignment). Team: 15-20% (4-year vest, 1-year cliff). Investors/VCs: 15-20% (2-3 year vest). Treasury: 10-15% (governed by DAO). Partners/advisors: 2-5%. Note: allocations adding >30% to investors + team signal centralization that communities and regulators increasingly scrutinize.' },
          { type: 'text', title: 'Vesting Mechanics', body: 'Linear vesting: equal monthly unlock over N years. Cliff: no tokens for first 12 months, then linear vesting begins. Step vesting: large unlock events at milestones. Standard: team 4-year linear + 1-year cliff. Investor 2-4 year linear. Why cliffs matter: a team member can\'t receive tokens and immediately leave. Cliff period = minimum alignment commitment. No cliff = immediate dumpable allocation.' },
          { type: 'highlight', title: 'Community Distribution Methods', body: 'Retroactive airdrop (most fair): reward past users. Fair launch: no pre-sale, everyone has equal access (rare). Liquidity bootstrapping pool: Dutch auction for price discovery. Staking rewards: earn by participating in the protocol. Grants: builders earn tokens for creating value. Competitive audit rewards. Each method attracts different communities and creates different token holder demographics.' },
          { type: 'text', title: 'Reading Unlock Calendars', body: 'Token.unlocks.app and Vesting.finance show upcoming token unlock events for all major projects. Large upcoming unlocks = potential sell pressure as insiders unlock vested tokens. Example: if 20% of supply unlocks in 3 months, expect selling from newly vested holders. Smart traders monitor unlock schedules to avoid holding through large unlock events, especially in bear markets.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Community should receive 40-50% for legitimate decentralization. 4-year vest + 1-year cliff for team is the standard. Large investor allocations signal centralization risk. Unlock calendars reveal future sell pressure — monitor them before any significant purchase.' },
        ]},
        { id: 'tok_beg_l3', title: 'Inflation and Deflation', slides: [
          { type: 'intro', title: 'Supply Dynamics Over Time', body: 'A token\'s supply changes over time through emissions (inflation) and burns (deflation). The net effect on supply — and therefore price, all else equal — is determined by the balance between these forces and the demand they serve or undermine.' },
          { type: 'text', title: 'Inflation: The Incentive Tool', body: 'New token emissions fund protocol growth: validator/staker rewards (ETH 1% annual inflation). Liquidity mining rewards (attract TVL). Contributor grants. Team vesting. Inflation creates sell pressure unless demand grows at least as fast. Unsustainably high inflation (100%+ annual) guarantees token price decline over time unless extraordinary growth compensates.' },
          { type: 'text', title: 'EIP-1559 and Deflationary ETH', body: 'EIP-1559 burns the transaction base fee. During high network activity, burns exceed new ETH issuance (staking rewards ~0.5% annually). Net result: ETH supply decreases. As of 2024, Ethereum has burned 4M+ ETH ($12B+ at current prices). In bull markets with high activity, ETH is net-deflationary — a structural demand driver for the asset.' },
          { type: 'highlight', title: 'Buyback and Burn', body: 'Some protocols use a portion of fees to buy their own token on the open market, then burn it. BNB: Binance burns 20% of quarterly profits in BNB until 50% of total supply is burned. 200M→100M BNB over time. This creates deflationary pressure proportional to protocol revenue. SNX (Synthetix): fees distributed to stakers. Curve: 50% of fees to veCRV holders. Each design creates different demand dynamics.' },
          { type: 'text', title: 'Real Yield vs Inflationary Yield', body: '"Real yield" = protocol revenue shared with token holders. If Uniswap activates its fee switch and distributes $1B/year to UNI holders, that\'s real yield — equivalent to a P/E ratio. "Inflationary yield" = you earn 50% APY but in newly created tokens that dilute everyone. Distinguish these: real yield sustains indefinitely; inflationary yield is temporary and self-defeating. Protocols with high APY from only token emissions are paying you with dilution.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Inflation funds growth but creates sell pressure. EIP-1559 made ETH deflationary through fee burning. Buyback-and-burn creates deflationary pressure from protocol revenue. Real yield (from protocol fees) is sustainable; inflationary yield (from token emissions) is temporary and dilutive.' },
        ]},
        { id: 'tok_beg_l4', title: 'Token Categories', slides: [
          { type: 'intro', title: 'Not All Tokens Are the Same', body: 'The crypto market has evolved from "coins" (Bitcoin) to a complex taxonomy of token types, each with different purposes, regulatory profiles, and valuation frameworks. Understanding what category a token falls into determines how to evaluate it.' },
          { type: 'text', title: 'Layer 1 Tokens', body: 'ETH, SOL, BNB, ADA, DOT: native tokens of base layer blockchains. Value: required to pay transaction fees, stake to secure the network, access the ecosystem. Valuation: proportional to network activity and adoption. These are the most fundamental tokens — they are the money of their respective ecosystems. Higher security, lower risk of total loss vs. application tokens.' },
          { type: 'text', title: 'Governance Tokens', body: 'UNI, AAVE, MKR, COMP: governance rights over protocols. Value: control over high-value protocol parameters. Risk: value is only governance rights if no fee switch — as discussed with UNI. Some governance tokens have strong fee capture (MKR buys back + burns from protocol revenue). Others are pure governance with no direct economic value (early UNI). Evaluate based on actual value capture, not just governance rights.' },
          { type: 'highlight', title: 'Stablecoins', body: 'USDT, USDC, DAI: designed to maintain $1 peg. Revenue model for issuers: Tether earns yield on US Treasury reserves backing USDT. Circle earns yield on USDC reserves. These businesses earned hundreds of millions in 2023 as interest rates rose. For holders: stablecoins provide DeFi utility without price risk. For issuers: holding user assets and investing them is extremely profitable.' },
          { type: 'text', title: 'Meme Coins and Cultural Tokens', body: 'DOGE, SHIB, PEPE, WIF: no utility beyond cultural significance and speculation. But cultural significance is surprisingly durable — Dogecoin has existed since 2013 and commands a $10B+ market cap through 3 full crypto cycles. Meme coins are marketing-first, community-second, tokenomics-last. Investment thesis: bet on the meme enduring. Risk: most memes don\'t endure. Volatility: extreme in both directions.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Layer 1 tokens are ecosystem money. Governance tokens derive value from fee capture, not just voting rights. Stablecoins are banker\'s tokens — issuers profit from user deposits. Meme coins are cultural bets on enduring attention. Different frameworks apply to each category.' },
        ]},
        { id: 'tok_beg_l5', title: 'Token Valuation Frameworks', slides: [
          { type: 'intro', title: 'How Much Should a Token Be Worth?', body: 'Unlike public equities with established valuation methods (P/E, DCF), crypto valuation is more art than science. But frameworks exist — and using them prevents the most egregious overpayment and helps identify genuinely undervalued assets.' },
          { type: 'text', title: 'Price-to-Sales (P/S) Ratio', body: 'P/S = market cap / annualized protocol revenue. Examples: Uniswap generates ~$500M/year in fees. At $5B market cap: P/S = 10x. Aave generates $200M+/year. GMX generates $100M+/year at much lower market caps. Compare P/S across similar protocols to identify relative value. A protocol with 5x P/S trading at the same price as one with 50x P/S may be significantly undervalued.' },
          { type: 'text', title: 'Total Value Locked (TVL) Ratio', body: 'TVL ratio = market cap / TVL. A protocol with $1B TVL and $100M market cap has a 0.1 TVL ratio. Compare across similar protocol categories. Low ratio = potentially undervalued relative to TVL. High ratio = high expectations baked in. DeFiLlama shows TVL and market cap side by side. Note limitation: TVL can be gamed through incentives — prioritize "organic" TVL from protocols without high emission rewards.' },
          { type: 'highlight', title: 'NVT Ratio for L1s', body: 'Network Value to Transactions ratio: market cap / daily on-chain transaction volume. Higher NVT = more of the valuation is speculation vs. real economic activity. Bitcoin\'s NVT historically peaks at bull market tops (more speculation per transaction) and troughs at bottoms (more value per speculation dollar). NVT divergence from price can signal over/undervaluation.' },
          { type: 'text', title: 'DCF for Tokens with Revenue Sharing', body: 'Tokens that capture protocol revenue can be valued like equities via Discounted Cash Flow: project 5-year revenue growth. Apply protocol\'s revenue share %. Discount at crypto-appropriate rate (20-30% for risk). Sum discounted cash flows. Compare to current market cap. This framework only works for tokens with actual, contractual revenue sharing — not governance-only tokens.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'P/S ratio compares market cap to protocol revenue. TVL ratio compares market cap to assets managed. NVT ratio measures speculation vs. real activity for L1s. DCF applies to revenue-sharing tokens. These are imperfect but essential tools for avoiding the most obvious overvaluation.' },
        ]},
      ],
      quiz: [
        { id: 'tok_beg_q1', question: 'What is Fully Diluted Valuation (FDV) and why does it matter more than market cap?', options: ['FDV is the same as market cap with a 10% premium', 'FDV = price × total supply (including unvested/locked tokens), revealing the true future market cap when all tokens unlock. Low market cap with high FDV means massive sell pressure incoming as tokens vest', 'FDV measures protocol revenue potential', 'FDV is only relevant for governance tokens'], correct: 1, explanation: 'Market cap (price × circulating supply) understates the real future supply. If a token has $500M market cap but $10B FDV, $9.5B in tokens will eventually enter the market as vesting unlocks. This creates persistent sell pressure. A $500M market cap token with $10B FDV is actually very expensive relative to its fully diluted value.' },
        { id: 'tok_beg_q2', question: 'Why is "real yield" from protocol fees more sustainable than "inflationary yield" from token emissions?', options: ['Real yield is regulated by financial authorities', 'Protocol fees are generated from actual user activity and are sustainable. Inflationary yield creates new tokens to pay rewards, diluting all holders — the effective yield is reduced by the inflation, and the practice is unsustainable if protocol revenue doesn\'t cover it', 'Real yield has no tax implications', 'Inflationary yield is mathematically identical to real yield'], correct: 1, explanation: 'If you earn 50% APY in a token that inflates 60% annually, your real return is negative. The token supply grows faster than demand can absorb, creating persistent sell pressure. Protocol fee revenue is external capital — real money from users. This can be distributed indefinitely as long as users pay fees. Inflationary yield stops being profitable when the emission rate exceeds new demand.' },
        { id: 'tok_beg_q3', question: 'What does a team vesting schedule with a 4-year vest and 1-year cliff accomplish?', options: ['It limits the total number of tokens the team receives', 'No tokens for the first year (cliff prevents immediate departure and dump), then linear vesting for 3 more years — aligning team incentives with 4-year protocol success rather than short-term pumps', 'It makes team tokens non-transferable forever', 'It distributes team tokens to the community after 4 years'], correct: 1, explanation: 'The cliff prevents a team member from joining, receiving tokens immediately, and leaving. The 4-year linear vest aligns team compensation with long-term protocol success — their financial upside comes from sustained growth, not a quick launch and dump. This is the market standard that sophisticated investors require before participation.' },
        { id: 'tok_beg_q4', question: 'How does EIP-1559 make ETH potentially deflationary?', options: ['It caps ETH issuance at 21 million like Bitcoin', 'The base fee from each transaction is burned (permanently destroyed) rather than paid to validators. During high network activity, burned ETH exceeds new ETH issuance from staking rewards, shrinking total supply', 'It reduces staking rewards to near zero', 'It burns a percentage of validator rewards automatically'], correct: 1, explanation: 'EIP-1559: each transaction has a base fee (set by algorithm based on demand) that is burned. Validators earn only tips and MEV. When Ethereum is busy, base fee × transaction count > new ETH from staking. Net supply decreases. 4M+ ETH has been burned since EIP-1559 launched. During peak bull market activity, ETH is significantly net-deflationary.' },
        { id: 'tok_beg_q5', question: 'What does a Price-to-Sales (P/S) ratio of 100x suggest about a protocol?', options: ['The protocol has very high revenue', 'The market is pricing in extremely high future growth — paying $100 for every $1 of current annual revenue. Either the growth materializes (justifying the premium) or the token is significantly overvalued at current price', 'The token is definitively undervalued', 'The protocol has 100x the TVL of competitors'], correct: 1, explanation: 'P/S = 100x means the market cap is 100 times current annual protocol revenue. Compare: Uniswap at 10x P/S vs. a new DEX at 100x P/S with similar current revenue. The 100x P/S demands exceptional future growth to justify — if the DEX doesn\'t 10x its market share, the P/S will compress and price will fall even if revenues grow.' },
      ],
    },
    {
      id: 'tokenomics_int',
      level: 'intermediate',
      title: 'Advanced Tokenomics',
      emoji: '🎯',
      description: 'Design token systems, understand emission schedules, and model incentive dynamics.',
      color: '#D97706',
      lessons: [
        { id: 'tok_int_l1', title: 'Emission Schedule Design', slides: [
          { type: 'intro', title: 'The Supply Roadmap', body: 'The emission schedule defines how new tokens enter circulation over time. It\'s the most consequential tokenomics decision after initial distribution — it determines inflation rate, incentive sustainability, and long-term price dynamics.' },
          { type: 'text', title: 'Decreasing Emissions: The Bitcoin Model', body: 'Bitcoin halves every 4 years: 50 → 25 → 12.5 → 6.25 → 3.125 BTC. Each halving reduces inflation by 50%. Net effect: predictable scarcity, hard supply cap, programmatic monetary policy. Altcoins mimicking this: many DeFi tokens use a 4-year decreasing emission schedule. The predictability allows market participants to price in future supply.' },
          { type: 'text', title: 'Modeling Emissions in Excel', body: 'Token emission modeling: Year 1: 30M tokens (30% of total). Year 2: 20M (20%). Year 3: 15M (15%). Year 4: 10M (10%). Remaining: 25% over years 5-10. At each year\'s price and adoption assumptions, calculate: circulating supply, FDV, sell pressure from new emissions, required demand growth to maintain price. If required demand growth exceeds realistic estimates, emissions are too high.' },
          { type: 'highlight', title: 'Emissions vs. Revenue', body: 'The sustainable threshold: emission value ≤ protocol revenue. If you emit $10M worth of tokens monthly but only generate $1M in revenue, the difference is paid from protocol reserves or inflation. This can last years in a bull market. In a bear market, it collapses rapidly. Build emission models that are sustainable at realistic, not peak, valuations.' },
          { type: 'text', title: 'Dynamic Emissions', body: 'Some protocols tie emission rates to protocol usage or market conditions. Olympus\'s rebase tokens dynamically adjusted supply to maintain price target (failed). Liquity\'s LQTY emissions are proportional to Stability Pool size. Dynamic emissions aim to match supply to demand — the hardest tokenomics problem to solve. Most implementations have been too complex and game-able.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Emission schedules must be modeled explicitly. Decreasing emissions (Bitcoin model) create predictable scarcity. Sustainable emissions should not exceed protocol revenue. Dynamic emissions are theoretically appealing but historically difficult to implement without gaming.' },
        ]},
        { id: 'tok_int_l2', title: 'Staking Mechanisms', slides: [
          { type: 'intro', title: 'Locking Tokens to Earn', body: 'Staking mechanisms encourage token holders to lock their tokens, reducing circulating supply and aligning long-term incentives. The design of staking determines whether it creates genuine alignment or mercenary participation.' },
          { type: 'text', title: 'Simple Staking Models', body: 'Basic staking: stake tokens, earn more tokens proportional to stake. Problem: pure inflation to stakers, funded by diluting non-stakers. No real value creation. Better model: stake tokens to earn protocol fees (like veCRV earning 50% of Curve trading fees). Here, stakers earn from real protocol activity — they benefit from usage growth, not just inflation.' },
          { type: 'text', title: 'veCRV Deep Dive', body: 'Lock 1 CRV for 1 year → 0.25 veCRV. Lock for 4 years → 1 veCRV. veCRV earns: 50% of Curve trading fees, boosted LP rewards (up to 2.5x), governance votes. veCRV decays over time — maximum at lock start, decreasing as unlock date approaches. Must re-lock to maintain maximum position. This creates continuous demand: holders must actively manage their lock to maintain benefits.' },
          { type: 'highlight', title: 'Liquid Staking Tokens', body: 'Problem with veCRV: locked tokens aren\'t liquid. Solution: Convex Finance issues cvxCRV — representing locked CRV, tradeable at slight discount to CRV. Wrapped staked tokens (stETH, rETH) represent staked ETH with liquidity. These "liquid staking" derivatives solve the lockup problem — you get staking benefits and token liquidity simultaneously. This innovation unlocked the restaking ecosystem.' },
          { type: 'text', title: 'Work Token Model', body: 'Work tokens require staking to perform valuable work in a protocol. LINK: data providers stake LINK as collateral to serve oracle data. If they serve bad data, LINK is slashed. The staked LINK creates security and aligns data providers with protocol health. This is the purest staking model: stake = access right + collateral + skin-in-the-game. No staking = no access. Clear economic alignment.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Staking for inflated tokens ≠ value creation. Staking for protocol fees = aligned incentives. veCRV is the archetypal model: lock duration → governance power and fee share. Liquid staking derivatives solve the lockup liquidity problem. Work tokens use staking as access control + collateral.' },
        ]},
        { id: 'tok_int_l3', title: 'Incentive Design', slides: [
          { type: 'intro', title: 'The Science of Alignment', body: 'Incentive design is the art and science of making rational self-interest align with collective good. In crypto, misaligned incentives are the root cause of most protocol failures — from mercenary liquidity to governance attacks to death spirals.' },
          { type: 'text', title: 'Mercenary Capital Problem', body: 'High-yield farming attracts capital that leaves the moment yields drop. Protocol A offers 500% APY in its token. Capital floods in. Token price rises (more buyers). APY drops (fixed emissions / more stakers). Capital exits. Token price crashes (sellers exit). APY needs to rise again (token is cheaper). Repeat until treasury is empty. This cycle has killed hundreds of protocols. It\'s not bad actors — it\'s rational behavior under bad incentive design.' },
          { type: 'text', title: 'Loyalty Incentives', body: 'Converting mercenary capital to loyal capital: time-weighted boosts (staking longer = higher rewards, Balancer\'s veBAL). NFT-gated enhanced rewards (holders of protocol NFTs earn extra). Progressive loyalty tiers (Tier 1 after 3 months, Tier 2 after 12 months). Retroactive loyalty rewards for longest holders. These create switching costs that retain capital through temporary yield droughts.' },
          { type: 'highlight', title: 'The Ponzi Threshold', body: 'When does a token economy become a Ponzi? When existing participant returns depend on new participant inflows rather than protocol value creation. Axie Infinity: SLP rewards paid to players came from new player purchases of Axies. No new players = no SLP demand = SLP price collapses = players exit = no new players. Test: can the economy sustain itself with zero new participants? If not, it\'s structurally a Ponzi.' },
          { type: 'text', title: 'Coordination Mechanisms', body: 'Advanced incentive mechanisms beyond staking: Prediction markets as governance (futarchy: bet on outcomes to govern). Quadratic funding (Gitcoin): matching amplifies small donations to public goods. Retroactive funding: reward what worked, not what might work. Harberger taxes: always-for-sale assets with self-assessed values. Each is a different mechanism for coordinating collective behavior toward social optima.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Mercenary capital follows incentives, not mission. Convert to loyalty through time-weighted boosts and progressive tiers. The Ponzi threshold test: can returns exist without new participants? Advanced mechanisms (quadratic funding, retroactive rewards) align more sophisticated collective behavior.' },
        ]},
        { id: 'tok_int_l4', title: 'Governance Token Economics', slides: [
          { type: 'intro', title: 'When Governance Has Value', body: 'Governance tokens are only valuable if the governance rights are valuable. Governing a protocol with $0 in revenue and no fee switch is worth $0. Governing a protocol with $1B in annual revenue that could route to holders is worth a great deal. This distinction drives the entire governance token valuation debate.' },
          { type: 'text', title: 'The Fee Switch Debate', body: 'The most important unresolved question in DeFi: should protocol revenues flow to governance token holders? Uniswap\'s fee switch: $1B+/year in potential revenue to UNI holders. Arguments for: aligns token value with protocol success, funds governance participation. Arguments against: legal risk (UNI as security), reduces LP incentives (LPs earn less), potential competitive disadvantage.' },
          { type: 'text', title: 'MKR: The Blueprint', body: 'MKR (MakerDAO) is the best example of a value-capturing governance token. Protocol revenue (stability fees from DAI loans + RWA yield) flows to: burn MKR from open market (reducing supply). Flop auctions (mint MKR to recapitalize if undercollateralized). MKR holders govern a money printer and bear the last-resort risk. The token captures real value proportional to protocol success. MKR\'s long-term price performance reflects this.' },
          { type: 'highlight', title: 'Governance Premiums', body: 'Some governance tokens trade at a "governance premium" — above what pure cash flow analysis would suggest. Why? Control over high-value parameters. The option to capture future fee switches. Strategic value of influence over widely used infrastructure. Protocol teams, VCs, and large DeFi players pay governance premiums for influence over protocols that affect their other investments.' },
          { type: 'text', title: 'Governance Minimization', body: 'Paradoxically, some of the most valuable protocols have the least governance: Uniswap v3 core contracts are effectively immutable. Bitcoin has extremely conservative governance. These protocols derive value from predictability and lack of governance attack surface. "Governance minimization" — reducing the surface area of governable parameters — is a design philosophy that prioritizes security over flexibility.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Governance value = control over valuable protocol parameters. Fee switches create direct cash flow to holders. MKR demonstrates the model: protocol revenue → buy back + burn + capitalization backstop. Governance minimization is the alternative philosophy — fewer governable parameters = less attack surface.' },
        ]},
        { id: 'tok_int_l5', title: 'Token Launch Strategies', slides: [
          { type: 'intro', title: 'The Art of the Launch', body: 'A token launch is a one-time event that sets the initial distribution, price discovery mechanism, and community composition permanently. Getting it wrong creates long-lasting problems: bad price discovery, concentrated whales, mercenary first buyers who dump immediately.' },
          { type: 'text', title: 'Liquidity Bootstrapping Pool (LBP)', body: 'Balancer LBPs use a Dutch auction mechanism for fair price discovery: start at a high price with high token weight (90/10). Token price decreases over time (72-96 hours) as the ratio shifts (50/50). Buyers buy in when they think price is fair. Result: distributes tokens across many participants at market-discovered prices, not a single fixed price that insiders game.' },
          { type: 'text', title: 'The DEX Launch (IDO)', body: 'Initial DEX Offering: create a Uniswap pool at your chosen initial price. Provide liquidity. Let the market discover price from day 1. Risk: first buyers get the lowest price and usually dump on later buyers. Mitigation: pair IDO with a strong community and product that creates genuine demand. Uniswap IDOs work best when the protocol already has significant traction before launch.' },
          { type: 'highlight', title: 'Exchange Listings', body: 'Tier 1 exchange listings (Binance, Coinbase) are the most impactful single event for token liquidity and discovery. But they cost: Coinbase listing requires significant legal work, no cash payment but significant compliance overhead. Binance listing has historically involved large token payments (community allegation). Both require strong protocols with genuine usage. Exchange listing without product-market fit = temporary pump and longer-term dump.' },
          { type: 'text', title: 'Launch Day Logistics', body: 'Essential day-1 setup: Uniswap/DEX pool funded. Coinmarketcap and CoinGecko listing submitted (takes 3-7 days). Smart contract verified on Etherscan. Tokenomics document published. Audit reports published. Token contract address announced on official channels. Analytics dashboard live. Vesting contracts visible. Discord channels for trading discussion. No launch is perfect — overcommunicate and expect to handle 100 questions/hour.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'LBPs enable fair Dutch auction price discovery. DEX IDOs require genuine pre-launch demand to prevent dump dynamics. Exchange listings are one-time leverage events — require product-market fit to sustain. Day-1 logistics set community confidence; underprepare and it collapses immediately.' },
        ]},
      ],
      quiz: [
        { id: 'tok_int_q1', question: 'What is the "mercenary capital" problem in DeFi yield farming?', options: ['Hackers exploiting high-yield protocols', 'Capital that deposits for high yield but exits immediately when yields drop — attracted by incentives, not the protocol, creating unstable TVL that evaporates when emissions decrease', 'VCs taking large allocations and dumping at launch', 'Institutional investors front-running retail users'], correct: 1, explanation: 'Mercenary capital follows the highest yield with no protocol loyalty. The cycle: high emissions attract capital → more stakers reduce per-staker yield → capital exits for higher yield elsewhere → TVL collapses → protocol desperate → increases emissions → more token inflation → devalues token → less attractive to next wave. Time-weighted staking boosts and loyalty programs partially solve this.' },
        { id: 'tok_int_q2', question: 'What makes MKR a better example of a governance token than UNI (at its current state)?', options: ['MKR has higher total supply', 'MKR captures actual protocol revenue through buyback-and-burn from MakerDAO\'s stability fees and RWA yield, making the token\'s value directly correlated with protocol success. UNI currently has no fee switch, so holders receive no direct economic value', 'MKR has more governance rights than UNI', 'MKR was launched before UNI'], correct: 1, explanation: 'UNI holders can vote on protocol changes but receive no share of Uniswap\'s $1B+ annual revenue. MKR is bought back from market with protocol revenue (stability fees) and burned — directly reducing supply and accruing value to holders. MKR holders also bear last-resort risk (Flop auctions mint MKR if DAI is undercollateralized). Governance + fee capture + risk exposure = aligned token.' },
        { id: 'tok_int_q3', question: 'What is the Ponzi threshold test for a token economy?', options: ['Whether the token has regulatory approval', 'Whether the economy can sustain existing participant returns without new participant inflows. If existing yields depend on new buyers entering, the system is structurally Ponzi-like and will collapse when growth slows', 'Whether more than 50% of tokens are staked', 'Whether the protocol has more than $1B in TVL'], correct: 1, explanation: 'The diagnostic question: remove all new participants from your mental model. Can existing participants still earn? If yes (from real protocol revenue, real yield), the economy is sustainable. If no (returns come from new deposits/buyers), then growth must continue indefinitely or the system collapses — the definition of a Ponzi structure.' },
        { id: 'tok_int_q4', question: 'Why does veCRV require continuous management to maintain maximum benefits?', options: ['veCRV tokens expire and must be renewed weekly', 'veCRV amount decays as the unlock date approaches (maximum at lock start, zero at unlock). To maintain maximum position, holders must re-lock before their lock expires — creating continuous CRV demand from existing holders', 'Curve protocol requires monthly KYC verification', 'veCRV is burned and replaced by new emissions each quarter'], correct: 1, explanation: 'veCRV represents time-remaining voting power. A 4-year lock gives 1 veCRV per CRV; a 3-year lock gives 0.75. As time passes, your veCRV decreases toward zero. To maintain full governance power and maximum fee share, you must re-lock. This creates constant "renewal demand" — existing holders must continuously buy and re-lock CRV to maintain their position.' },
        { id: 'tok_int_q5', question: 'Why is a Liquidity Bootstrapping Pool (LBP) considered a fairer launch mechanism than a fixed-price IDO?', options: ['LBPs require KYC to prevent whale dominance', 'The Dutch auction mechanism starts price high and decreases over time, discouraging bots and whales from buying the entire supply at launch. It distributes tokens across many participants at market-discovered prices rather than a fixed price that insiders game', 'LBPs only allow small purchases', 'LBPs distribute tokens proportionally to existing holders'], correct: 1, explanation: 'Fixed-price IDOs: bots buy everything at $0.01 and sell at $0.10 to real buyers. LBP: starts high (bots don\'t want to buy at the peak), price decreases over 72-96 hours. Buyers enter when they think the price is fair relative to project value. Result: more organic distribution, more price discovery, less initial dump from people who bot-sniped the launch at the lowest possible price.' },
      ],
    },
    {
      id: 'tokenomics_exp',
      level: 'expert',
      title: 'Protocol Economy Design',
      emoji: '🌐',
      description: 'Design complete token economies, model complex incentive dynamics, and stress-test protocol mechanics.',
      color: '#D97706',
      lessons: [
        { id: 'tok_exp_l1', title: 'Game Theory in Tokenomics', slides: [
          { type: 'intro', title: 'Mechanism Design for Crypto', body: 'Tokenomics is applied mechanism design and game theory: create rules such that rational agents, pursuing their own interests, collectively produce good protocol outcomes. Every tokenomics design is a game — model how rational players will respond before deploying to mainnet.' },
          { type: 'text', title: 'Nash Equilibria in Token Systems', body: 'A Nash Equilibrium: a state where no player can improve their outcome by unilaterally changing strategy. Design tokenomics where the Nash Equilibrium is "participate honestly and hold long-term." The failure: most tokenomics have Nash Equilibria at "extract maximum yield and exit." Olympus DAO\'s (3,3) was a game theory construct: both stake (3,3) > one stakes one sells (1,3). In practice, the defection payoff eventually dominated.' },
          { type: 'text', title: 'Schelling Points and Coordination', body: 'A Schelling Point is a focal point that rational actors coordinate on without communication. Stablecoins use the $1 Schelling Point — everyone expects $1, so everyone acts to maintain $1. ETH difficulty bomb was a Schelling Point forcing the move to PoS. Schelling Points are powerful coordination tools: design your protocol with natural Schelling Points that coordinate behavior toward desired outcomes.' },
          { type: 'highlight', title: 'The Reflexivity Problem', body: 'Soros\'s reflexivity principle: market participants\' beliefs change the fundamentals they\'re trying to predict. In crypto: high token price → attracts more participants → more demand → higher price → feedback loop. Low price → fewer participants → less demand → lower price → death spiral. Every tokenomics design must consider reflexivity: how does price affecting fundamentals affect price? Systems that amplify both up and down are fragile (Olympus).' },
          { type: 'text', title: 'Adversarial Simulation', body: 'Before launch: simulate adversarial actors with 10x, 100x more capital than you expect. A whale with $1B can do what? Can they break your collateralization? Drain your treasury via governance? Manipulate your oracle? Each vulnerability found in simulation is free. Each vulnerability found on mainnet costs user funds. Run war games — have separate teams try to break your tokenomics from every angle.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Tokenomics is mechanism design: model Nash Equilibria and ensure honest participation dominates. Schelling Points coordinate without communication. Reflexivity creates feedback loops — design systems resilient to both positive and negative spirals. Adversarial simulation finds vulnerabilities before users pay for them.' },
        ]},
        { id: 'tok_exp_l2', title: 'Agent-Based Modeling', slides: [
          { type: 'intro', title: 'Simulating Complex Economies', body: 'Agent-based models (ABM) simulate a population of agents with different strategies, capital, and decision rules — then observe emergent system-level behavior. This approach reveals dynamics that equation-based models miss, including phase transitions and tipping points.' },
          { type: 'text', title: 'cadCAD: The Crypto Standard', body: 'cadCAD (complex adaptive dynamics Computer-Aided Design) is the open-source Python framework for crypto tokenomics modeling. Developed originally for MakerDAO. Define: agent types (holders, traders, liquidity providers, stakers). State variables (token price, supply, TVL). Policy functions (how agents respond to state). Dynamics (how policies change state). Then run thousands of Monte Carlo simulations.' },
          { type: 'text', title: 'Key Simulation Scenarios', body: 'Market crash scenarios: BTC drops 70% in 30 days. How does your collateralization hold? How many liquidations occur? Does the liquidation cascade cause further crashes? Bank run scenarios: 50% of depositors exit simultaneously. Does your liquidity hold? Governance attack scenarios: whale accumulates 40% of tokens over 6 months and executes a malicious proposal. How do other holders respond?' },
          { type: 'highlight', title: 'MakerDAO\'s Modeling Success', body: 'MakerDAO is the most modeled protocol in DeFi. Their risk team uses cadCAD to test collateral parameters before every major change. When USDC collateralization was increased, models predicted liquidation cascades at specific ETH price levels. Those levels were watched; emergency governance actions were pre-planned. The result: MakerDAO survived the March 2020 crash that others didn\'t.' },
          { type: 'text', title: 'Token Terminal and On-Chain Data', body: 'For real tokenomics analysis: Token Terminal tracks P/S, P/E, revenue, fees across all major protocols. DeFiLlama tracks TVL, stablecoin supply, DEX volume. Dune Analytics enables custom on-chain queries. Nansen tracks wallet behavior and smart money flows. The combination of ABM simulation + on-chain empirical data is the most rigorous tokenomics research approach available.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'cadCAD enables Monte Carlo simulation of token economies under adversarial conditions. Model market crash, bank run, and governance attack scenarios explicitly. MakerDAO\'s survival of multiple crypto crashes validates the value of rigorous pre-deployment simulation.' },
        ]},
        { id: 'tok_exp_l3', title: 'Cross-Protocol Tokenomics', slides: [
          { type: 'intro', title: 'Composable Token Economies', body: 'DeFi composability means tokens interact with each other in complex ways — a single token can simultaneously be collateral, a yield-bearing asset, a governance vote, and a fee-paying utility. Cross-protocol tokenomics models these interactions explicitly.' },
          { type: 'text', title: 'Nested Token Value', body: 'stETH is: Ethereum + staking yield + Lido governance rights. cvxCRV is: CRV + veCRV benefits + Convex liquidity. These nested tokens capture value from multiple underlying layers. The complexity: a failure in any layer (Lido validator slashing, Curve exploit) affects all nested derivatives. Value from composition also creates risk from composition.' },
          { type: 'text', title: 'Liquidity Flywheel Analysis', body: 'Map how liquidity flows between protocols: ETH → stETH (Lido) → Aave collateral → borrow USDC → Curve pool → earn CRV → lock for veCRV → earn more CRV + fees. Each step in this chain creates demand for multiple tokens simultaneously. Disrupting one step — stETH depeg, Aave liquidity crisis, Curve hack — cascades through the entire chain.' },
          { type: 'highlight', title: 'Protocol-Owned Liquidity Math', body: 'POL (Protocol-Owned Liquidity) modeling: Protocol A offers bonds: deposit ETH/TokenA LP → receive 1,000 TokenA at 20% discount in 5 days. The protocol acquires LP tokens permanently. LP earns fees forever. Model the break-even: if LP fees generate > cost of 20% discount within 6 months, POL is accretive. Olympus\'s original POL math was sound; the tokenomics collapse was reflexivity not POL.' },
          { type: 'text', title: 'Cross-Chain Tokenomics', body: 'Multi-chain token deployment creates complexity: same token on Ethereum, Arbitrum, Solana with bridges between. Arbitrage ensures price parity but creates: bridge risk (bridge exploits drain one chain\'s token). Governance fragmentation (same governance token, different voting weight per chain). Liquidity fragmentation (deeper on one chain). Model cross-chain token flows and bridge security as tokenomics risks.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Composable tokens accumulate value from multiple layers but inherit their risks. Liquidity flywheel analysis traces how shocks propagate through protocol chains. POL math requires break-even modeling of discount vs. fee revenue. Cross-chain tokens add bridge risk and governance/liquidity fragmentation.' },
        ]},
        { id: 'tok_exp_l4', title: 'Sustainable Protocol Design', slides: [
          { type: 'intro', title: 'Designing for the Next Decade', body: 'The crypto landscape is littered with protocols that were profitable at peak but unsustainable at scale. Sustainable protocol design means building systems that generate real value, retain users without mercenary incentives, and improve their competitive position over time.' },
          { type: 'text', title: 'Network Effects in Crypto', body: 'The strongest moat in crypto is network effects: Uniswap\'s liquidity depth → better prices → more volume → more fees → more LP incentive → more liquidity. Bitcoin\'s security → more holders → more security budget from fees → more security. Curve\'s TVL → lower slippage → more volume → more fees → more LP rewards → more TVL. Network effects compound — the leader captures disproportionate share of activity.' },
          { type: 'text', title: 'Revenue Model Sustainability', body: 'Sustainable revenue = real fees from real users for real utility. Test: if you removed all token incentives tomorrow, would users still pay fees to use your protocol? Uniswap: yes (traders need best execution). Aave: yes (borrowers need leverage). GMX: yes (traders need perpetuals). These protocols can sustain with zero token incentives because they provide genuine utility. Most protocols fail this test.' },
          { type: 'highlight', title: 'The Competitive Moat Analysis', body: 'Assess your protocol\'s moat: liquidity depth (requires capital, time to replicate). Technical innovation (can be forked). Network effects (hardest to replicate). Brand/trust (immense flywheel value). Community (partially transferable but slow to rebuild). A fork can replicate code in minutes but can\'t replicate Uniswap\'s liquidity depth, brand trust, or 5-year security track record. Moats are your competitive protection.' },
          { type: 'text', title: 'Long-Term Treasury Management', body: '100-year thinking for DAOs: if your protocol is to exist for 100 years (longer than most corporations), your treasury strategy must outlast multiple market cycles. Diversify: 20-30% stablecoins for 5-10 years of runway. Yield-generating assets (RWAs) for treasury growth. Reserve for ecosystem grants. Never spend treasury on marketing or token buybacks during bear markets — preserve optionality. Spend on development and ecosystem that compound value over time.' },
          { type: 'summary', title: 'Lesson Complete! +20 XP', body: 'Network effects are the most defensible moat. Sustainability test: would users pay fees without token incentives? Moat analysis identifies what a fork can and cannot replicate. 100-year treasury thinking means stablecoin runway + yield-generating reserves + ecosystem investment — not marketing spend in bear markets.' },
        ]},
        { id: 'tok_exp_l5', title: 'The Future of Tokenomics', slides: [
          { type: 'intro', title: 'Open Problems in Token Design', body: 'Tokenomics as a discipline is 10 years old. The fundamental problems — aligning incentives, preventing governance attacks, creating sustainable token value — are not fully solved. The researchers and designers working on these problems are defining the financial infrastructure of the next decade.' },
          { type: 'text', title: 'Mechanism Design Frontiers', body: 'Unsolved problems: How to design a stablecoin that maintains peg without overcollateralization or algorithmic failure? How to create governance that\'s both decentralized and fast? How to prevent MEV extraction from redistributing value away from users? How to build cross-chain token economies that are both composable and secure? These are open problems attracting the best minds in cryptoeconomics.' },
          { type: 'text', title: 'AI in Token Economy Design', body: 'AI-optimized tokenomics: AI models trained on all historical DeFi data to optimize emission schedules, governance parameters, and collateralization ratios. AI agents participating in governance to analyze proposals. AI-managed treasuries that dynamically rebalance based on market conditions. These are active research areas — the combination of AI optimization and on-chain verification could produce tokenomics designs beyond human intuition.' },
          { type: 'highlight', title: 'Cryptoeconomic Security Budgets', body: 'The long-term security question for all PoS chains: as block rewards decrease, do transaction fees generate enough security budget? Ethereum\'s security depends on validators earning sufficient rewards to justify staked ETH opportunity cost. If fees can\'t replace diminishing issuance, validator exit rate increases, reducing security. This is the long-term challenge for every PoS chain with decreasing emissions.' },
          { type: 'text', title: 'The Protocol City Analogy', body: 'Vitalik Buterin\'s analogy: protocols are like cities. Early cities attracted residents with cheap land (low fees, high rewards). As the city grew, land became expensive (higher fees, lower yields) but the established infrastructure justified the premium. Protocol sustainability works the same: early subsidized adoption → network effects → sustainable fee-based revenue. The city analogy suggests that patience + network effects + genuine utility always wins.' },
          { type: 'summary', title: 'Module Complete! +20 XP', body: 'Open problems: sustainable stablecoin design, decentralized-fast governance, MEV redistribution. AI in tokenomics is an active frontier. Long-term PoS security depends on fee markets replacing diminishing issuance. The city analogy: patient network effect building beats all short-term incentive engineering.' },
        ]},
      ],
      quiz: [
        { id: 'tok_exp_q1', question: 'What is a Nash Equilibrium and why does its location determine tokenomics success?', options: ['The point where token supply equals demand', 'A stable state where no rational actor can improve their outcome by unilaterally changing strategy. Sustainable tokenomics designs place the Nash Equilibrium at "participate honestly and hold" — not "extract and exit"', 'The optimal governance token distribution', 'A token price target set by protocol governance'], correct: 1, explanation: 'If the Nash Equilibrium of your token system is "stake as long as rewards are high, then exit" — that\'s what rational actors will do. Successful tokenomics (like veCRV) creates a Nash Equilibrium at long-term lock: maximum benefits require maximum lock, so rational actors who want maximum benefits all lock for maximum duration. The NE aligns individual interest with protocol health.' },
        { id: 'tok_exp_q2', question: 'What is cadCAD and why is it used for tokenomics modeling?', options: ['A programming language for smart contracts', 'A Python framework for complex adaptive dynamics simulation — enables modeling how populations of agents with different strategies interact under different market conditions, revealing system-level emergent behavior', 'A token audit tool', 'A governance voting platform'], correct: 1, explanation: 'cadCAD models populations of agents (holders, traders, stakers, arbitrageurs) with defined decision rules, then simulates their interactions under different market scenarios. MakerDAO used cadCAD to model the March 2020 crash and pre-plan emergency governance responses. It reveals tipping points, cascade risks, and optimal parameter ranges that equation-based models miss.' },
        { id: 'tok_exp_q3', question: 'What is the sustainability test for a DeFi protocol\'s tokenomics?', options: ['Whether the protocol has been audited by multiple firms', 'Would users still pay fees to use the protocol if all token incentives were removed tomorrow? If yes, the protocol has genuine utility. If no, it depends on subsidized usage that is unsustainable without continuous emissions', 'Whether the protocol\'s TVL exceeds $1B', 'Whether governance token holders receive fee revenue'], correct: 1, explanation: 'Incentives attract users; genuine utility retains them. Uniswap without UNI incentives: traders still use it for best execution. Aave without AAVE incentives: borrowers still use it for leverage. A protocol where usage collapses without emissions is a protocol whose "usage" is purely mercenary — sustainable only as long as the subsidy lasts.' },
        { id: 'tok_exp_q4', question: 'What is the reflexivity problem in token economies?', options: ['Token prices reflecting real-time blockchain data', 'Market participants\' beliefs change the fundamentals they\'re trying to predict — high token price attracts more participants (improving fundamentals), while low price repels them. This creates self-reinforcing spirals in both directions, making token systems fragile if designed to amplify rather than dampen these effects', 'Smart contracts executing based on oracle price feeds', 'Governance votes being influenced by token price movements'], correct: 1, explanation: 'Reflexivity: belief → action → reality → updated belief. In crypto, high price → FOMO → more buyers → higher price → more FOMO (upward spiral). Low price → FUD → more sellers → lower price → more FUD (downward spiral). Systems that amplify reflexivity (Olympus, highly leveraged protocols) are existentially fragile. Designs that dampen reflexivity (gradual emissions, vesting, circuit breakers) are more stable.' },
        { id: 'tok_exp_q5', question: 'How does the "protocol city" analogy explain long-term protocol sustainability?', options: ['Protocols should be governed like city governments', 'Early protocols offer cheap participation (high rewards, low fees) to attract initial users. As network effects develop, the premium for established infrastructure justifies higher fees — sustainable revenue replaces initial subsidies, like a city that no longer needs to offer free land once it has infrastructure residents value', 'Protocols should acquire physical real estate', 'Token holders should have voting rights proportional to their stake like city taxpayers'], correct: 1, explanation: 'Cities attract early residents with cheap land (pre-network-effect subsidies). As the city grows, established infrastructure, liquidity, and network effects make it valuable despite higher costs. Protocols follow the same arc: subsidized early growth → network effects → fee-sustainable maturity. The patient path to sustainability requires building genuine network effects, not perpetual emission subsidies.' },
      ],
    },
  ],
};

export default tokenomics;
